import React, { useState, useEffect } from 'react';

async function fetchCopyTrading() {
  const res = await fetch('/api/copytrading');
  const json = await res.json();
  return json.data;
}

async function fetchAccounts() {
  const res = await fetch('/api/copytrading/accounts');
  const json = await res.json();
  return json.data;
}

async function updateConfig(updates) {
  const res = await fetch('/api/copytrading/config', {
    method: 'PUT',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(updates),
  });
  const json = await res.json();
  return json.data;
}

async function toggleCopyTrading(enabled) {
  const res = await fetch('/api/copytrading/toggle', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ enabled }),
  });
  const json = await res.json();
  return json.data;
}

export default function CopyTrading() {
  const [data, setData] = useState(null);
  const [accounts, setAccounts] = useState([]);
  const [saving, setSaving] = useState(false);
  const [saved, setSaved] = useState(false);
  const [localConfig, setLocalConfig] = useState(null);

  const load = async () => {
    const [ct, acc] = await Promise.all([fetchCopyTrading(), fetchAccounts()]);
    setData(ct);
    setAccounts(acc);
    if (!localConfig) setLocalConfig(ct.config);
  };

  useEffect(() => {
    load();
    const interval = setInterval(load, 5000);
    return () => clearInterval(interval);
  }, []);

  const save = async () => {
    setSaving(true);
    try {
      await updateConfig(localConfig);
      setSaved(true);
      setTimeout(() => setSaved(false), 2000);
      load();
    } catch (e) { console.error(e); }
    finally { setSaving(false); }
  };

  const toggle = async () => {
    const newEnabled = !localConfig.enabled;
    setLocalConfig(c => ({ ...c, enabled: newEnabled }));
    await toggleCopyTrading(newEnabled);
    load();
  };

  const update = (key, value) => {
    setLocalConfig(c => ({ ...c, [key]: value }));
  };

  if (!data || !localConfig) return (
    <div style={{ color: 'var(--text3)', padding: 40 }}>Loading copy trading...</div>
  );

  const masterAccount = accounts.find(a => a.key === localConfig.masterAccountKey);
  const followerAccount = accounts.find(a => a.key === localConfig.followerAccountKey);
  const isConfigured = localConfig.masterAccountKey && localConfig.followerAccountKey &&
    localConfig.masterAccountKey !== localConfig.followerAccountKey;

  return (
    <div>
      <div className="page-header">
        <div className="page-title">Copy Trading</div>
        <div className="page-subtitle">Mirror trades from master to follower account</div>
      </div>

      {/* Status Banner */}
      <div className="section" style={{
        padding: '16px 20px',
        background: localConfig.enabled && isConfigured ? 'rgba(0,212,170,0.08)' : 'var(--panel)',
        border: `1px solid ${localConfig.enabled && isConfigured ? 'rgba(0,212,170,0.3)' : 'var(--border)'}`,
        borderRadius: 'var(--radius)',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'space-between',
        gap: 16,
      }}>
        <div>
          <div style={{
            fontFamily: 'var(--font-display)',
            fontSize: 14,
            fontWeight: 600,
            color: localConfig.enabled && isConfigured ? 'var(--accent)' : 'var(--text)',
          }}>
            {localConfig.enabled && isConfigured
              ? '● Copy Trading Active'
              : localConfig.enabled && !isConfigured
              ? '⚠ Enabled but not configured'
              : '○ Copy Trading Disabled'}
          </div>
          <div style={{ fontSize: 11, color: 'var(--text3)', marginTop: 4 }}>
            {isConfigured
              ? `${masterAccount?.label || localConfig.masterAccountKey} → ${followerAccount?.label || localConfig.followerAccountKey} · ${localConfig.fixedLotSize} lots`
              : 'Select master and follower accounts below'}
          </div>
        </div>
        <div
          className="toggle-wrap"
          onClick={isConfigured ? toggle : undefined}
          style={{ opacity: isConfigured ? 1 : 0.4, cursor: isConfigured ? 'pointer' : 'not-allowed' }}
        >
          <div className={`toggle ${localConfig.enabled ? 'on' : ''}`} />
          <span className="toggle-label">{localConfig.enabled ? 'ON' : 'OFF'}</span>
        </div>
      </div>

      {/* Stats Row */}
      <div className="section grid-3">
        <div className="stat-card">
          <div className="stat-label">Trades Copied</div>
          <div className="stat-value accent">{data.totalCopied ?? 0}</div>
          <div className="stat-sub">Since last restart</div>
        </div>
        <div className="stat-card">
          <div className="stat-label">Trades Closed</div>
          <div className="stat-value">{data.totalClosed ?? 0}</div>
          <div className="stat-sub">Follower closures</div>
        </div>
        <div className="stat-card">
          <div className="stat-label">Active Mirrors</div>
          <div className="stat-value" style={{ color: 'var(--accent2)' }}>
            {Object.keys(data.config?.copiedTrades || {}).length}
          </div>
          <div className="stat-sub">Currently open</div>
        </div>
      </div>

      {/* Configuration */}
      <div className="section card">
        <div className="card-title">Configuration</div>

        {accounts.length < 2 && (
          <div style={{
            padding: '12px 16px',
            background: 'var(--yellow-dim)',
            border: '1px solid rgba(255,211,42,0.3)',
            borderRadius: 'var(--radius)',
            color: 'var(--yellow)',
            fontSize: 12,
            marginBottom: 20,
          }}>
            ⚠ You need at least 2 connected accounts to use copy trading.
            Add a second account in your .env file.
          </div>
        )}

        <div className="grid-2" style={{ marginBottom: 20 }}>
          {/* Master Account */}
          <div style={{
            padding: 16,
            background: 'var(--bg3)',
            border: '1px solid var(--border)',
            borderRadius: 'var(--radius)',
            borderTop: '3px solid var(--accent)',
          }}>
            <div style={{ fontSize: 10, color: 'var(--accent)', textTransform: 'uppercase', letterSpacing: '0.1em', marginBottom: 12 }}>
              ★ Master Account
            </div>
            <div className="field">
              <label>Select Master</label>
              <select
                value={localConfig.masterAccountKey}
                onChange={e => update('masterAccountKey', e.target.value)}
              >
                <option value="">— Select account —</option>
                {accounts
                  .filter(a => a.key !== localConfig.followerAccountKey)
                  .map(a => (
                    <option key={a.key} value={a.key}>
                      {a.label} ({a.platform.toUpperCase()})
                    </option>
                  ))}
              </select>
            </div>
            <div style={{ fontSize: 11, color: 'var(--text3)', marginTop: 10 }}>
              Trades opened here will be copied to the follower
            </div>
          </div>

          {/* Follower Account */}
          <div style={{
            padding: 16,
            background: 'var(--bg3)',
            border: '1px solid var(--border)',
            borderRadius: 'var(--radius)',
            borderTop: '3px solid var(--accent2)',
          }}>
            <div style={{ fontSize: 10, color: 'var(--accent2)', textTransform: 'uppercase', letterSpacing: '0.1em', marginBottom: 12 }}>
              ◎ Follower Account
            </div>
            <div className="field">
              <label>Select Follower</label>
              <select
                value={localConfig.followerAccountKey}
                onChange={e => update('followerAccountKey', e.target.value)}
              >
                <option value="">— Select account —</option>
                {accounts
                  .filter(a => a.key !== localConfig.masterAccountKey)
                  .map(a => (
                    <option key={a.key} value={a.key}>
                      {a.label} ({a.platform.toUpperCase()})
                    </option>
                  ))}
              </select>
            </div>
            <div style={{ fontSize: 11, color: 'var(--text3)', marginTop: 10 }}>
              This account will automatically mirror the master
            </div>
          </div>
        </div>

        {/* Trade Settings */}
        <div style={{ borderTop: '1px solid var(--border)', paddingTop: 20, marginBottom: 20 }}>
          <div style={{ fontSize: 11, color: 'var(--text3)', textTransform: 'uppercase', letterSpacing: '0.1em', marginBottom: 16 }}>
            Trade Settings
          </div>
          <div className="grid-2">
            <div className="field">
              <label>Fixed Lot Size (follower)</label>
              <input
                type="number"
                step="0.01"
                min="0.01"
                value={localConfig.fixedLotSize}
                onChange={e => update('fixedLotSize', parseFloat(e.target.value))}
              />
            </div>
            <div style={{ display: 'flex', alignItems: 'center' }}>
              <div
                className="toggle-wrap"
                onClick={() => update('copySlTp', !localConfig.copySlTp)}
                style={{ cursor: 'pointer' }}
              >
                <div className={`toggle ${localConfig.copySlTp ? 'on' : ''}`} />
                <div>
                  <div className="toggle-label">Copy SL & TP from master</div>
                  <div style={{ fontSize: 10, color: 'var(--text3)', marginTop: 3 }}>
                    If off, bot rules apply instead
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>

        <button className="btn btn-primary" onClick={save} disabled={saving}>
          {saving ? 'Saving...' : saved ? '✓ Saved!' : 'Save Configuration'}
        </button>
      </div>

      {/* Active Mirrors */}
      {Object.keys(data.config?.copiedTrades || {}).length > 0 && (
        <div className="section card">
          <div className="card-title">Active Mirrors</div>
          <div className="table-wrap">
            <table>
              <thead>
                <tr>
                  <th>Master Position ID</th>
                  <th>Follower Position ID</th>
                  <th>Status</th>
                </tr>
              </thead>
              <tbody>
                {Object.entries(data.config.copiedTrades).map(([masterId, followerId]) => (
                  <tr key={masterId}>
                    <td style={{ fontFamily: 'var(--font-mono)', fontSize: 11 }}>{masterId}</td>
                    <td style={{ fontFamily: 'var(--font-mono)', fontSize: 11 }}>{followerId}</td>
                    <td><span className="badge badge-buy">Active</span></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* Recent Errors */}
      {data.errors?.length > 0 && (
        <div className="section card">
          <div className="card-title" style={{ color: 'var(--red)' }}>Recent Errors</div>
          {data.errors.slice(-5).reverse().map((e, i) => (
            <div key={i} style={{
              padding: '8px 12px',
              background: 'var(--red-dim)',
              borderRadius: 'var(--radius)',
              marginBottom: 6,
              fontSize: 11,
            }}>
              <span style={{ color: 'var(--text3)', marginRight: 10 }}>
                {new Date(e.time).toLocaleTimeString()}
              </span>
              <span style={{ color: 'var(--red)' }}>{e.message}</span>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
